<template><div class="document-page" v-loading="loading"><div class="document-header"><div><el-button link @click="router.push('/inventory/adjustments')"><el-icon><ArrowLeft/></el-icon> 返回</el-button><h1>库存调整详情</h1></div><div><el-button v-if="detail?.status==='DRAFT'" type="success" @click="approve">审核入账</el-button><el-button v-if="detail?.status==='DRAFT'" type="danger" plain @click="cancel">取消调整</el-button></div></div><el-card><template #header><div class="section-title"><span>调整信息</span><el-tag :type="statusType(detail?.status)">{{statusLabel(detail?.status)}}</el-tag></div></template><el-descriptions v-if="detail" :column="3" border><el-descriptions-item label="调整单号">{{detail.adjustmentNo}}</el-descriptions-item><el-descriptions-item label="业务日期">{{detail.adjustmentDate}}</el-descriptions-item><el-descriptions-item label="调整仓库">{{detail.warehouseName}}</el-descriptions-item><el-descriptions-item label="调整类型">{{typeLabel(detail.adjustmentType)}}</el-descriptions-item><el-descriptions-item label="总数量">{{detail.totalQuantity}}</el-descriptions-item><el-descriptions-item label="成本金额">{{detail.totalAmount}}</el-descriptions-item><el-descriptions-item label="调整原因">{{detail.reason}}</el-descriptions-item><el-descriptions-item label="备注">{{detail.remark||'-'}}</el-descriptions-item></el-descriptions></el-card><el-card class="section-card"><template #header><div class="section-title"><span>调整明细</span><small>共 {{detail?.items?.length||0}} 项商品</small></div></template><el-table :data="detail?.items||[]" border stripe><el-table-column type="index" label="序号" width="60"/><el-table-column prop="productCode" label="商品编码" width="140"/><el-table-column prop="productName" label="商品名称" min-width="190"/><el-table-column prop="unitName" label="单位" width="80"/><el-table-column prop="quantity" label="数量" width="110" align="right"/><el-table-column prop="unitCost" label="单位成本" width="120" align="right"/><el-table-column prop="amount" label="成本金额" width="120" align="right"/><el-table-column prop="reason" label="明细原因" min-width="180"/></el-table></el-card></div></template>
<script setup lang="ts">import{onMounted,ref}from'vue';import{useRoute,useRouter}from'vue-router';import{ElMessage,ElMessageBox}from'element-plus';import{approveInventoryAdjustment,cancelInventoryAdjustment,getInventoryAdjustment}from'@/api/inventory';const route=useRoute(),router=useRouter(),id=Number(route.params.id),loading=ref(false),detail=ref<any>(null);onMounted(load);async function load(){loading.value=true;try{detail.value=(await getInventoryAdjustment(id)).data}finally{loading.value=false}}function typeLabel(v:string){return v==='DECREASE'?'报损减少':'库存增加'}function statusLabel(v:string){return({DRAFT:'草稿',COMPLETED:'已完成',CANCELLED:'已取消'}as any)[v]||v}function statusType(v:string){return({DRAFT:'info',COMPLETED:'success',CANCELLED:'danger'}as any)[v]||''}async function approve(){await ElMessageBox.confirm(`审核后将直接${detail.value.adjustmentType==='DECREASE'?'减少':'增加'}库存，是否继续？`,'审核入账',{type:'warning'});await approveInventoryAdjustment(id);ElMessage.success('库存调整已入账');load()}async function cancel(){await ElMessageBox.confirm('确定取消该调整单吗？','取消调整',{type:'warning'});await cancelInventoryAdjustment(id);ElMessage.success('调整单已取消');load()}</script>
<style scoped>.document-page{padding-bottom:24px}.document-header{min-height:66px;display:flex;align-items:center;justify-content:space-between;margin:-16px -20px 16px;padding:0 22px;background:#fff;border-bottom:1px solid #edf0f5}.document-header>div,.section-title{display:flex;align-items:center;gap:10px}.document-header h1{margin:0;font-size:19px}.section-card{margin-top:14px}.section-title{justify-content:space-between}.section-title span{font-size:16px;font-weight:600}.section-title small{color:#a1a8b3}</style>
